    // Helper methods for Application Users SYNC
    // Starts a brand-new, independent transaction for each user
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void processSingleUserUpsertTransaction(InventoryApplicationUserDTO user) {
        String userId = user.getId();
        String applicationId = user.getApplicationId();
        Integer status = user.getStatus();
        // Step 1: Upsert the user
        Integer rowsAffected = applicationUserRepository.upsertApplicationUsers(user.getId(), user.getTechnicianId(), user.getEmail(), user.getType());
        if (rowsAffected == null || rowsAffected == 0) {
            throw new RuntimeException("Failed to upsert user: " + userId);
        }
        // Step 2: Get managedSoftwareId
        String managedSoftwareId = managedSoftwareRepository.findIdByApplicationId(applicationId);
        if (managedSoftwareId == null) {
            throw new RuntimeException("No managed software found for applicationId: " + applicationId);
        }
        // Step 3: Handle user based on status
        if (status != null && status == 0) {
            // OUT = 0 then assign managedSoftwareId
            Integer updated = applicationUserRepository.updateManagedSoftwareIdByUserId(userId, managedSoftwareId);
            if (updated == null || updated == 0) {
                throw new RuntimeException("Failed to update managedSoftwareId for OUT user: " + userId);
            }
            log.info("Updated OUT user: {} with managedSoftwareId: {}", userId, managedSoftwareId);
        } else if (status != null && status == 1) {
            // IN = 1 then delete the user
            Integer deleted = applicationUserRepository.deleteApplicationUsersById(userId);
            if (deleted == null || deleted == 0) {
                throw new RuntimeException("Failed to delete IN user: " + userId);
            }
            log.info("Deleted IN user: {} for application: {}", userId, applicationId);
        }
        // Step 4: Risk status update (only if email is available)
        // If user is OUT (0) in Inventory => risk status = 0 (compliant) and if user is IN (1) in Inventory => risk status = 1 (risky) for any email match
        int riskStatus = (user.getStatus() == 0) ? 0 : 1;
        boolean success = this.updateRiskStatusForMatchingUsers(user, managedSoftwareId, riskStatus);
        if (!success) {
            throw new RuntimeException("Risk status update failed for user: " + userId);
        }
        log.info("Successfully processed upsert for user: {}", userId);
    }

    // Starts a brand-new, independent transaction for each user
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void processSingleUserDeleteTransaction(InventoryApplicationUserDTO user) {
        String userId = user.getId();
        String applicationId = user.getApplicationId();
        Integer status = user.getStatus();
        // Step 1: Fetch managed software ID
        String managedSoftwareId = managedSoftwareRepository.findIdByApplicationId(applicationId);
        if (managedSoftwareId == null) {
            throw new RuntimeException("No managedSoftwareId found for applicationId: " + applicationId);
        }
        // Step 2: Delete the user (status = 1)
        /* When the OUT user transaction is deleted in the inventory then it will be made as IN and then sent to us for delete
        *  When the IN user transaction is deleted in the inventory then it will be made as OUT and then sent to us for upsert */
        if (status != null && status == 1) {
            Integer deleted = applicationUserRepository.deleteApplicationUsersById(userId);
            if (deleted == null || deleted == 0) {
                throw new RuntimeException("Failed to delete application user: " + userId);
            }
            log.info("Deleted application user: {} from application user table for applicationId: {}", userId, applicationId);
        } else {
            log.info("Skipping deletion for user: {} as status is not IN (1). Current status: {}", userId, status);
        }
        // Step 3: Update risk status to risky (1)
        // Since the user is deleted from Inventory, we consider them as risky if any email match is found
        int riskStatus = 1;
        boolean success = this.updateRiskStatusForMatchingUsers(user, managedSoftwareId, riskStatus);
        if (!success) {
            throw new RuntimeException("Risk status update failed for user: " + userId);
        }
        log.info("Successfully processed deletion for user: {}", userId);
    }

    private boolean updateRiskStatusForMatchingUsers(InventoryApplicationUserDTO applicationUser, String managedSoftwareId, int riskStatus) {
        String userId = applicationUser.getId();
        String userEmail = applicationUser.getEmail();
        // Note: Handling records with technician_id instead of email (if email is not available) is pending for now
        // These records will be skipped in the current implementation
        // Get device specs linked to this managed software
        Set<String> deviceSpecificationIds = deviceInstalledAppsRepository.getDeviceSpecIdsByManagedSoftwareId(managedSoftwareId);
        List<DeviceSpecification> deviceSpecs = deviceSpecificationRepository.findByIdIn(deviceSpecificationIds);
        for (DeviceSpecification spec : deviceSpecs) {
            String deviceUserEmail = spec.getEmail();
            String deviceSpecId = spec.getId();
            if (deviceUserEmail != null && !deviceUserEmail.trim().isEmpty() && deviceUserEmail.equalsIgnoreCase(userEmail)) {
                Integer updated = deviceInstalledAppsRepository.updateRiskStatusByDeviceSpecId(deviceSpecId, managedSoftwareId, riskStatus);
                if (updated == null || updated == 0) {
                    log.warn("No rows affected when updating device: {} for userId: {} with riskStatus = {}", deviceSpecId, userId, riskStatus);
                    return false;
                }
            }
        }
        return true; // all matched record updates succeeded
    }
